  KEY `idx_sys_login_info_status` (`tenant_id`,`status`),
  KEY `idx_sys_login_info_user` (`tenant_id`,`user_name`)
) ENGINE=InnoDB AUTO_INCREMENT=64 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='系统访问记录';
