    JOIN `tmp_admin_module_menu` parent_seed
      ON parent_seed.`menu_code` = child_seed.`parent_code`
    JOIN `sys_menu` parent
      ON parent.`tenant_id` = '0'
     AND parent.`deleted` = 0
     AND (
          (parent_seed.`perms` <> '' AND parent.`perms` = parent_seed.`perms`)
